import hashlib
import json
from pathlib import Path
from dataclasses import dataclass, field

@dataclass
class DocRecord:
    function_name: str
    file_path: str
    source_hash: str         # SHA-256 of function body at last doc generation
    docstring: str           # last generated docstring
    is_stale: bool = False

class DocStalenessTracker:
    def __init__(self, db_path: str = ".doc_hashes.json"):
        self._db_path = Path(db_path)
        self._records: dict[str, DocRecord] = {}
        if self._db_path.exists():
            raw = json.loads(self._db_path.read_text())
            self._records = {
                k: DocRecord(**v) for k, v in raw.items()
            }

    def _key(self, file_path: str, function_name: str) -> str:
        return f"{file_path}::{function_name}"

    @staticmethod
    def _hash(source: str) -> str:
        return hashlib.sha256(source.encode()).hexdigest()[:16]

    def check_and_update(self, file_path: str, function_name: str, source: str) -> bool:
        """Return True if docstring is stale (source changed since last doc generation)."""
        key = self._key(file_path, function_name)
        current_hash = self._hash(source)
        record = self._records.get(key)
        if record is None:
            return True  # Never documented
        return record.source_hash != current_hash

    def record_generation(
        self, file_path: str, function_name: str, source: str, docstring: str
    ) -> None:
        key = self._key(file_path, function_name)
        self._records[key] = DocRecord(
            function_name=function_name,
            file_path=file_path,
            source_hash=self._hash(source),
            docstring=docstring,
        )
        self._db_path.write_text(
            json.dumps({k: vars(v) for k, v in self._records.items()}, indent=2)
        )

    def find_stale_in_file(self, file_path: str) -> list[str]:
        """Return names of functions whose docs are stale in a file."""
        source = Path(file_path).read_text()
        tree = ast.parse(source)
        source_lines = source.splitlines()
        stale = []
        for node in ast.walk(tree):
            if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                continue
            snippet = "\n".join(source_lines[node.lineno - 1:node.end_lineno])
            if self.check_and_update(file_path, node.name, snippet):
                stale.append(node.name)
        return stale


# Example: pre-commit hook or CI step
tracker = DocStalenessTracker()
for py_file in Path("src/").rglob("*.py"):
    stale = tracker.find_stale_in_file(str(py_file))
    if stale:
        print(f"{py_file}: stale docs for {stale}")

#!/usr/bin/env python3
"""CI script: fail if any public function in changed files lacks a docstring."""
import ast
import subprocess
import sys
from pathlib import Path

def get_changed_python_files() -> list[str]:
    result = subprocess.run(
        ["git", "diff", "--name-only", "HEAD~1", "HEAD"],
        capture_output=True, text=True
    )
    return [f for f in result.stdout.splitlines() if f.endswith(".py")]

def find_missing_docs(file_path: str) -> list[str]:
    source = Path(file_path).read_text()
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return []
    missing = []
    for node in ast.walk(tree):
        if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            continue
        if node.name.startswith("_"):
            continue  # skip private/dunder
        has_doc = (
            node.body
            and isinstance(node.body[0], ast.Expr)
            and isinstance(node.body[0].value, ast.Constant)
            and isinstance(node.body[0].value.value, str)
        )
        if not has_doc:
            missing.append(f"{file_path}:{node.lineno} {node.name}()")
    return missing

def main() -> int:
    changed_files = get_changed_python_files()
    all_missing: list[str] = []
    for f in changed_files:
        if not Path(f).exists():
            continue  # deleted file
        all_missing.extend(find_missing_docs(f))
    if all_missing:
        print("Missing docstrings in changed files:")
        for item in all_missing:
            print(f"  {item}")
        print("\nRun: python -m doc_assistant add-missing --files <file>")
        return 1
    return 0

if __name__ == "__main__":
    sys.exit(main())
